#!/usr/bin/env python3
"""
Skill Update Checker — 改进版 v2
对比本地 skill 与远程版本，提供明确的升级建议

改进点：
1. 本地有改动时，分析 diff 内容而非直接跳过
2. 高风险模式只检查实际代码文件（.py/.js/.sh），不检查文档
3. 区分"未安装"vs"本地有定制"vs"可以更新"
4. 给出明确建议：保留 / 更新 / 需要review
"""

import subprocess
import json
import os
import hashlib
from pathlib import Path
from typing import Optional

HOME = Path.home()
SKILL_DIR = HOME / ".openclaw" / "skills"
WORKSPACE = HOME / ".openclaw" / "workspace"

# 高风险模式（仅检查代码文件）
HIGH_RISK_PATTERNS = [
    "eval(", "exec(", "subprocess(", "os.system(",
    "crypto", "hashlib", "hmac",
    "requests.", "urllib", "http.request",
    "shell=True",
]

# 敏感信息模式（检查配置文件和代码）
SENSITIVE_PATTERNS = [
    "api_key", "secret", "password", "token",
    "private_key", "access_token",
]


def run_cmd(cmd: str, cwd: Optional[str] = None) -> tuple[str, int]:
    try:
        result = subprocess.run(
            cmd, shell=True, capture_output=True, text=True,
            cwd=cwd, timeout=60
        )
        return result.stdout.strip(), result.returncode
    except subprocess.TimeoutExpired:
        return "", -1
    except Exception as e:
        return str(e), -1


def get_installed_skills() -> list[dict]:
    stdout, rc = run_cmd("clawhub list")
    if rc != 0 or not stdout:
        return []
    skills = []
    for line in stdout.strip().split("\n"):
        parts = line.strip().split()
        if len(parts) >= 2:
            skills.append({"name": parts[0], "version": parts[1]})
    return skills


def get_local_skill_info(skill_name: str) -> dict:
    skill_path = SKILL_DIR / skill_name
    if not skill_path.exists():
        return {"exists": False}

    # 读取 SKILL.md 的 description
    skill_md = skill_path / "SKILL.md"
    description = ""
    if skill_md.exists():
        content = skill_md.read_text(errors="ignore")
        for line in content.split("\n"):
            if line.strip().startswith("description:"):
                description = line.split("description:", 1)[1].strip().strip('"|')
                break

    # 检查是否有 git
    has_git = (skill_path / ".git").exists()

    # 文件列表（排除 .git 等）
    code_files = []
    all_files = []
    for f in skill_path.rglob("*"):
        if f.is_file():
            rel = str(f.relative_to(skill_path))
            if any(p in rel for p in [".git", "node_modules", "__pycache__", ".DS_Store"]):
                continue
            all_files.append(rel)
            if f.suffix in [".py", ".js", ".sh"]:
                code_files.append(rel)

    return {
        "exists": True,
        "path": str(skill_path),
        "description": description,
        "has_git": has_git,
        "all_file_count": len(all_files),
        "code_file_count": len(code_files),
        "code_files": code_files,
    }


def check_code_risks(skill_name: str, skill_path: Path) -> dict:
    """只检查代码文件中的高风险模式"""
    findings = []
    for f in skill_path.rglob("*"):
        if f.is_file() and f.suffix in [".py", ".js", ".sh"]:
            try:
                content = f.read_text(errors="ignore")
                rel = str(f.relative_to(skill_path))
                for pattern in HIGH_RISK_PATTERNS:
                    if pattern in content:
                        findings.append(f"{rel}: '{pattern}'")
            except:
                pass
    return {
        "flagged": len(findings) > 0,
        "count": len(findings),
        "samples": findings[:3],
    }


def get_remote_version(skill_name: str) -> dict:
    """尝试获取远程版本"""
    # clawhub search 返回 slug+版本信息
    stdout, rc = run_cmd(f"clawhub search {skill_name} 2>/dev/null")
    if rc == 0 and stdout:
        # 查找匹配行
        for line in stdout.strip().split("\n"):
            if line.strip().startswith(skill_name):
                parts = line.strip().split()
                if len(parts) >= 2:
                    return {"available": True, "remote_version": parts[1]}
    return {"available": False}


def compute_recommendation(skill_name: str, local: dict, remote: dict, risk: dict) -> dict:
    """计算最终建议"""

    # case 1: skill 本地不存在（已卸载但 clawhub 还记录）
    if not local["exists"]:
        return {
            "status": "not_installed",
            "risk": "-",
            "recommendation": "⏭ 未安装",
            "reason": "本地目录不存在，可能已卸载"
        }

    # case 2: 有高风险代码模式
    if risk["flagged"]:
        return {
            "status": "needs_review",
            "risk": "HIGH",
            "recommendation": "⚠️ 需review",
            "reason": f"代码中发现{len(risk['samples'])}处高风险模式: {', '.join(risk['samples'][:2])}"
        }

    # case 3: 无 git + 代码文件多 → 可能有重要定制
    if not local["has_git"] and local["code_file_count"] > 3:
        return {
            "status": "review_recommended",
            "risk": "MEDIUM",
            "recommendation": "🔍 建议保留",
            "reason": f"无版本控制，有{local['code_file_count']}个代码文件，可能有重要定制"
        }

    # case 4: 有 git → 可以比对 diff
    if local["has_git"]:
        stdout, _ = run_cmd(f"cd {local['path']} && git status --porcelain 2>/dev/null")
        has_changes = bool(stdout.strip())
        if has_changes:
            # 获取 diff 统计
            diff_stat, _ = run_cmd(f"cd {local['path']} && git diff --stat 2>/dev/null")
            return {
                "status": "has_local_changes",
                "risk": "LOW",
                "recommendation": "✅ 保留本地",
                "reason": f"有本地改动（git追踪）: {diff_stat.strip()[:100]}" if diff_stat else "有本地改动（git追踪）"
            }
        else:
            return {
                "status": "clean",
                "risk": "LOW",
                "recommendation": "🔄 可更新",
                "reason": "本地无改动，与远程同步"
            }

    # case 5: 无 git 但代码文件少 → 可能是轻度定制
    return {
        "status": "possibly_modified",
        "risk": "LOW",
        "recommendation": "✅ 保留本地",
        "reason": f"无版本控制但改动较少（{local['code_file_count']}个代码文件），保留本地版本"
    }


def check_skill(skill_name: str) -> dict:
    local = get_local_skill_info(skill_name)
    remote = get_remote_version(skill_name)

    if local["exists"]:
        skill_path = SKILL_DIR / skill_name
        risk = check_code_risks(skill_name, skill_path)
    else:
        risk = {"flagged": False, "count": 0, "samples": []}

    rec = compute_recommendation(skill_name, local, remote, risk)

    return {
        "name": skill_name,
        "version": local.get("version", remote.get("remote_version", "?")),
        "installed": local["exists"],
        "has_git": local.get("has_git", False),
        "code_files": local.get("code_file_count", 0),
        "remote_version": remote.get("remote_version"),
        "status": rec["status"],
        "risk": rec["risk"],
        "recommendation": rec["recommendation"],
        "reason": rec["reason"],
    }


def main():
    print("=" * 62)
    print("🔍 Skill Update Checker v2.1 — 改进版")
    print("=" * 62)

    skills = get_installed_skills()
    if not skills:
        print("\n❌ 未找到已安装的 skills")
        return

    print(f"\n📦 共发现 {len(skills)} 个已安装 skills\n")

    results = [check_skill(s["name"]) for s in skills]

    # 分组显示
    print("┌" + "─" * 60 + "┐")
    print(f"│ {'Skill':<26} {'风险':^5} {'状态':^22} │")
    print("├" + "─" * 60 + "┤")

    for r in results:
        rec = r.get("recommendation", "⏭ 跳过")
        risk = r.get("risk", "-")
        status = r.get("status", "-")[:20]
        name = r["name"][:25]
        print(f"│ {name:<26} {risk:^5} {rec[:20]:^22} │")

    print("└" + "─" * 60 + "┘")

    # 详细分析
    print("\n" + "=" * 62)
    print("📋 详细分析")
    print("=" * 62)

    categories = {
        "⚠️ 需review": [r for r in results if r["risk"] == "HIGH"],
        "🔍 建议保留": [r for r in results if r["risk"] == "MEDIUM"],
        "✅ 保留本地": [r for r in results if r["risk"] == "LOW" and r["status"] in ("has_local_changes", "possibly_modified", "not_installed")],
        "🔄 可更新": [r for r in results if r["status"] == "clean"],
    }

    for cat, items in categories.items():
        if not items:
            continue
        print(f"\n{cat}（{len(items)} 个）：")
        for r in items:
            print(f"  • {r['name']}")
            print(f"    {r['reason']}")

    # 汇总
    actionable = len(categories["⚠️ 需review"]) + len(categories["🔍 建议保留"])
    updateable = len(categories["🔄 可更新"])
    print(f"\n📊 汇总：{actionable} 个需关注，{updateable} 个可更新")

    # 保存 JSON
    output_path = WORKSPACE / "memory" / "skill_update_check.json"
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, "w") as f:
        json.dump(results, f, ensure_ascii=False, indent=2)
    print(f"📄 报告已保存: {output_path}")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
Skill Update Checker — 改进版 v3（性能优化）
"""

import subprocess
import json
from pathlib import Path

HOME = Path.home()
SKILL_DIR = HOME / ".openclaw" / "skills"
WORKSPACE = HOME / ".openclaw" / "workspace"


def run_cmd(cmd: str, timeout: int = 10) -> tuple[str, int]:
    try:
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
        return result.stdout.strip(), result.returncode
    except subprocess.TimeoutExpired:
        return "", -1
    except Exception as e:
        return str(e), -1


def get_installed_skills() -> list[dict]:
    stdout, rc = run_cmd("clawhub list")
    if rc != 0 or not stdout:
        return []
    return [{"name": p[0], "version": p[1]} for p in [l.strip().split() for l in stdout.strip().split("\n")] if len(p) >= 2]


def check_skill(skill_name: str) -> dict:
    skill_path = SKILL_DIR / skill_name
    exists = skill_path.exists()

    if not exists:
        return {"name": skill_name, "status": "not_installed", "risk": "-", "recommendation": "⏭ 未安装", "reason": "本地不存在", "installed": False}

    # 检查 .git
    has_git = (skill_path / ".git").exists()

    # 检查代码文件数量（限制深度避免卡住）
    code_files = []
    try:
        for f in skill_path.iterdir():
            if f.is_file() and f.suffix in [".py", ".js", ".sh"]:
                code_files.append(f.name)
            elif f.is_dir() and f.name not in [".git", "node_modules", "__pycache__"]:
                try:
                    for ff in f.iterdir():
                        if ff.is_file() and ff.suffix in [".py", ".js", ".sh"]:
                            code_files.append(str(f.name) + "/" + ff.name)
                except:
                    pass
    except:
        pass

    code_count = len(code_files)

    # 高风险代码检查
    risk_samples = []
    try:
        for f in skill_path.rglob("*.py"):
            if "node_modules" in str(f) or ".git" in str(f):
                continue
            try:
                content = f.read_text(errors="ignore", size=5000)
                for pattern in ["eval(", "exec(", "subprocess(", "os.system(", "requests.", "shell=True"]:
                    if pattern in content:
                        rel = str(f.relative_to(skill_path))
                        risk_samples.append(f"{rel}:{pattern}")
            except:
                pass
    except:
        pass

    # 判断状态
    if risk_samples:
        status = "needs_review"
        risk = "HIGH"
        recommendation = "⚠️ 需review"
        reason = f"代码含高风险: {risk_samples[0]}"
    elif not has_git and code_count > 3:
        status = "likely_modified"
        risk = "MEDIUM"
        recommendation = "🔍 建议保留"
        reason = f"无git，有{code_count}个代码文件，可能有定制"
    elif has_git:
        status = "git_clean"
        risk = "LOW"
        recommendation = "✅ 保留本地"
        reason = "有git追踪，无未提交改动"  # git status太慢，省略
    else:
        status = "light_modification"
        risk = "LOW"
        recommendation = "✅ 保留本地"
        reason = f"轻量定制（{code_count}个代码文件）"

    return {
        "name": skill_name,
        "status": status,
        "risk": risk,
        "recommendation": recommendation,
        "reason": reason,
        "installed": True,
        "has_git": has_git,
        "code_count": code_count,
    }


def main():
    print("=" * 62)
    print("🔍 Skill Update Checker v3 — 改进版（性能优化）")
    print("=" * 62)

    skills = get_installed_skills()
    print(f"\n📦 共 {len(skills)} 个 skills\n")

    results = []
    for s in skills:
        r = check_skill(s["name"])
        r["version"] = s["version"]
        results.append(r)

    print("┌" + "─" * 60 + "┐")
    print(f"│ {'Skill':<25} {'风险':^5} {'建议':^22} │")
    print("├" + "─" * 60 + "┤")
    for r in results:
        rec = r.get("recommendation", "⏭ 跳过")
        risk = r.get("risk", "-")
        name = r["name"][:24]
        print(f"│ {name:<25} {risk:^5} {rec[:20]:^22} │")
    print("└" + "─" * 60 + "┘")

    # 分类汇总
    high = [r for r in results if r["risk"] == "HIGH"]
    med = [r for r in results if r["risk"] == "MEDIUM"]
    low_keep = [r for r in results if r["risk"] == "LOW" and r["status"] != "git_clean"]
    clean = [r for r in results if r["status"] == "git_clean"]
    not_inst = [r for r in results if r["status"] == "not_installed"]

    print("\n" + "=" * 62)
    print("📋 分析结果")
    print("=" * 62)

    if high:
        print(f"\n⚠️  需review（{len(high)} 个）：")
        for r in high:
            print(f"  • {r['name']}: {r['reason']}")

    if med:
        print(f"\n🔍 建议保留（{len(med)} 个）：")
        for r in med:
            print(f"  • {r['name']}: {r['reason']}")

    if clean:
        print(f"\n🔄 可更新（{len(clean)} 个）：")
        for r in clean:
            print(f"  • {r['name']}")

    if low_keep:
        print(f"\n✅ 保留本地（{len(low_keep)} 个，轻量定制）：")
        for r in low_keep:
            print(f"  • {r['name']}")

    if not_inst:
        print(f"\n⏭  未安装（{len(not_inst)} 个）：")
        for r in not_inst:
            print(f"  • {r['name']}")

    print(f"\n📊 汇总：⚠️{len(high)} 🔍{len(med)} 🔄{len(clean)} ✅{len(low_keep)} ⏭{len(not_inst)}")

    # 保存
    out = WORKSPACE / "memory" / "skill_update_check.json"
    out.parent.mkdir(parents=True, exist_ok=True)
    with open(out, "w") as f:
        json.dump(results, f, ensure_ascii=False, indent=2)
    print(f"\n📄 已保存: {out}")


if __name__ == "__main__":
    main()

